<?php
namespace App\Actions;
use App\Models\{InventoryMovement,MaterialPurchase};use Illuminate\Support\Facades\DB;
class CreateMaterialPurchaseAction{public function execute(array $data): MaterialPurchase{return DB::transaction(function() use($data){$items=$data['items'];$tagIds=$data['tag_ids']??[];unset($data['items'],$data['tag_ids']);$purchase=MaterialPurchase::create($data+['total_amount'=>0]);$total='0';foreach($items as $item){$line=round((float)$item['quantity']*(float)$item['unit_price'],2);$purchaseItem=$purchase->items()->create($item+['total_price'=>$line]);InventoryMovement::create(['project_id'=>$purchase->project_id,'material_id'=>$item['material_id'],'date'=>$purchase->date,'type'=>'in','quantity'=>$item['quantity'],'unit_price'=>$item['unit_price'],'amount'=>$line,'source_type'=>$purchaseItem::class,'source_id'=>$purchaseItem->id,'comment'=>'Покупка материалов #'.$purchase->id]);$total=(string)((float)$total+$line);} $purchase->update(['total_amount'=>round((float)$total,2)]);$purchase->tags()->sync($tagIds);return $purchase->load('items','tags');});}}
